// Extract document content from webhook payload
const items = $input.all();
const item = items[0].json;

// Try to get file data from binary or body
let documentContent = '';
let imageBase64 = null;

if (item.body && item.body.document_base64) {
  imageBase64 = item.body.document_base64;
  documentContent = 'Image document provided as base64';
} else if (item.body && item.body.document_text) {
  documentContent = item.body.document_text;
} else if (item.body && item.body.text) {
  documentContent = item.body.text;
} else {
  documentContent = JSON.stringify(item.body || item);
}

return [{
  json: {
    documentContent,
    imageBase64,
    hasImage: !!imageBase64
  }
}];

